package org.apache.commons.lang3.mutable;

/**
 * Helper class that implements byte arithmetic operations used by {@link MutableByte}.
 *
 * <p>All methods are available as static helpers for backwards compatibility and as
 * instance methods via {@link ByteArithmetic} for dependency inversion.</p>
 */
public class MutableByteArithmetic implements ByteArithmetic {

    public MutableByteArithmetic() {
        // allow instantiation for interface-based usage
    }

    /* Static helper methods (renamed to avoid duplicate signatures with instance methods) */
    public static byte doAdd(byte current, byte operand) {
        return (byte) (current + operand);
    }

    public static byte doAdd(byte current, Number operand) {
        return doAdd(current, operand.byteValue());
    }

    public static byte doSubtract(byte current, byte operand) {
        return (byte) (current - operand);
    }

    public static byte doSubtract(byte current, Number operand) {
        return doSubtract(current, operand.byteValue());
    }

    public static byte doIncrement(byte current) {
        return doAdd(current, (byte) 1);
    }

    public static byte doDecrement(byte current) {
        return doSubtract(current, (byte) 1);
    }

    public static byte doAddAndGet(byte current, byte operand) {
        return doAdd(current, operand);
    }

    public static byte doAddAndGet(byte current, Number operand) {
        return doAdd(current, operand);
    }

    public static byte doGetAndAdd(byte current, byte operand) {
        return current;
    }

    public static byte doGetAndAdd(byte current, Number operand) {
        return current;
    }

    public static byte doIncrementAndGet(byte current) {
        return doIncrement(current);
    }

    public static byte doGetAndIncrement(byte current) {
        return current;
    }

    public static byte doDecrementAndGet(byte current) {
        return doDecrement(current);
    }

    public static byte doGetAndDecrement(byte current) {
        return current;
    }

    /* Instance implementations delegating to static helpers */

    @Override
    public byte add(byte current, byte operand) {
        return MutableByteArithmetic.doAdd(current, operand);
    }

    @Override
    public byte add(byte current, Number operand) {
        return MutableByteArithmetic.doAdd(current, operand);
    }

    @Override
    public byte subtract(byte current, byte operand) {
        return MutableByteArithmetic.doSubtract(current, operand);
    }

    @Override
    public byte subtract(byte current, Number operand) {
        return MutableByteArithmetic.doSubtract(current, operand);
    }

    @Override
    public byte increment(byte current) {
        return MutableByteArithmetic.doIncrement(current);
    }

    @Override
    public byte decrement(byte current) {
        return MutableByteArithmetic.doDecrement(current);
    }

    @Override
    public byte addAndGet(byte current, byte operand) {
        return MutableByteArithmetic.doAddAndGet(current, operand);
    }

    @Override
    public byte addAndGet(byte current, Number operand) {
        return MutableByteArithmetic.doAddAndGet(current, operand);
    }

    @Override
    public byte getAndAdd(byte current, byte operand) {
        return MutableByteArithmetic.doGetAndAdd(current, operand);
    }

    @Override
    public byte getAndAdd(byte current, Number operand) {
        return MutableByteArithmetic.doGetAndAdd(current, operand);
    }

    @Override
    public byte incrementAndGet(byte current) {
        return MutableByteArithmetic.doIncrementAndGet(current);
    }

    @Override
    public byte getAndIncrement(byte current) {
        return MutableByteArithmetic.doGetAndIncrement(current);
    }

    @Override
    public byte decrementAndGet(byte current) {
        return MutableByteArithmetic.doDecrementAndGet(current);
    }

    @Override
    public byte getAndDecrement(byte current) {
        return MutableByteArithmetic.doGetAndDecrement(current);
    }
}
